export type SetupCooldowns = Record<string, number>;

/** Normalized chart overlay event emitted per detection */
export type ChartOverlayEvent = {
  ts: string;
  instrument: string;
  setup_type: SetupType;
  direction: "long" | "short";
  decision_type: "TRADE" | "REJECTED" | "PASS";
  scores: {
    structure: number;
    order_flow: number;
    recall: number;
    final: number;
    sk_sequence: number;
    cvd_slope: number;
  };
  entry_price: number;
  sl_price: number;
  tp_price: number;
  labels: string[];
  regime: Regime;
  sk_bias: SKBias;
  meets_threshold: boolean;
  reason: string;
